// Defines how to resolve a workflow id conflict with a *running* workflow.
// The default policy is WORKFLOW_ID_CONFLICT_POLICY_USE_EXISTING.
// Note that WORKFLOW_ID_CONFLICT_POLICY_FAIL is an invalid option.
//
// See `workflow_id_reuse_policy` for handling a workflow id duplication with a *closed*
// workflow.
type WorkflowIDConflictPolicy string

const (
	WorkflowIDConflictPolicyFail              WorkflowIDConflictPolicy = "WORKFLOW_ID_CONFLICT_POLICY_FAIL"
	WorkflowIDConflictPolicyTerminateExisting WorkflowIDConflictPolicy = "WORKFLOW_ID_CONFLICT_POLICY_TERMINATE_EXISTING"
	WorkflowIDConflictPolicyUnspecified       WorkflowIDConflictPolicy = "WORKFLOW_ID_CONFLICT_POLICY_UNSPECIFIED"
	WorkflowIDConflictPolicyUseExisting       WorkflowIDConflictPolicy = "WORKFLOW_ID_CONFLICT_POLICY_USE_EXISTING"
)

// Defines whether to allow re-using the workflow id from a previously *closed* workflow.
// The default policy is WORKFLOW_ID_REUSE_POLICY_ALLOW_DUPLICATE.
//
// See `workflow_id_reuse_policy` for handling a workflow id duplication with a *running*
// workflow.
type WorkflowIDReusePolicy string

const (
	WorkflowIDReusePolicyAllowDuplicate           WorkflowIDReusePolicy = "WORKFLOW_ID_REUSE_POLICY_ALLOW_DUPLICATE"
	WorkflowIDReusePolicyAllowDuplicateFailedOnly WorkflowIDReusePolicy = "WORKFLOW_ID_REUSE_POLICY_ALLOW_DUPLICATE_FAILED_ONLY"
	WorkflowIDReusePolicyRejectDuplicate          WorkflowIDReusePolicy = "WORKFLOW_ID_REUSE_POLICY_REJECT_DUPLICATE"
	WorkflowIDReusePolicyTerminateIfRunning       WorkflowIDReusePolicy = "WORKFLOW_ID_REUSE_POLICY_TERMINATE_IF_RUNNING"
	WorkflowIDReusePolicyUnspecified              WorkflowIDReusePolicy = "WORKFLOW_ID_REUSE_POLICY_UNSPECIFIED"
)


type TemporalNexusPayloadVisitorFunc func([]*commonv1.Payload) ([]*commonv1.Payload, error)

type TemporalNexusPayloadVisitor func(*commonv1.Payload, TemporalNexusPayloadVisitorFunc, bool) (*commonv1.Payload, error)

